// WOA 悬浮注入 — 在 WPS协作 DevTools 控制台粘贴运行
// 再次运行可关闭
(function(){var id='cc-float-frame';var f=document.getElementById(id);if(f){f.remove();return;}var docUrl='';var activeSpan=document.querySelector('[class*=active] span');var docTitle=activeSpan?activeSpan.textContent.trim():'';var wvs=[...document.querySelectorAll('webview')];for(var i=wvs.length-1;i>=0;i--){var s=wvs[i].src||'';var m=s.match(/365\.kdocs\.cn\/l\/[A-Za-z0-9]+/);if(m){docUrl=s.split('?')[0];break;}}if(!docUrl){var links=document.body.innerHTML.match(/https:\/\/365\.kdocs\.cn\/l\/[A-Za-z0-9]+/g);if(links)docUrl=links[links.length-1];}f=document.createElement('iframe');f.id=id;f.src='http://localhost:5174/panel?mode=float&docUrl='+encodeURIComponent(docUrl)+'&docTitle='+encodeURIComponent(docTitle);f.allow='clipboard-write';f.style.cssText='position:fixed;right:8px;bottom:8px;width:80px;height:80px;border:none;z-index:99999;background:transparent;border-radius:50%;';f.setAttribute('allowtransparency','true');document.body.appendChild(f);window.addEventListener('message',function(e){if(e.data?.type==='__CC_PANEL__'){if(e.data.open){f.style.width='440px';f.style.height='600px';f.style.borderRadius='12px';}else{f.style.width='80px';f.style.height='80px';f.style.borderRadius='50%';}}});})();
